    create table article (
        discount_percent float(24),
        is_best_seller boolean,
        is_featured boolean,
        is_flash_sale boolean,
        price float(53) not null,
        vat float(24),
        created_at timestamp(6),
        flash_sale_ends_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        brand varchar(255),
        created_by varchar(255),
        description TEXT,
        ean varchar(255) unique,
        img varchar(255),
        name varchar(255) not null,
        reference_partner varchar(255),
        sku varchar(255) not null unique,
        updated_by varchar(255),
        status enum ('ACTIVE','ARCHIVED','DRAFT') not null,
        primary key (id)
    );

    create table article_categories (
        categories_id integer not null,
        article_id bigint not null
    );

    create table authentication (
        created_at timestamp(6),
        updated_at timestamp(6),
        user_id varchar(128) not null,
        created_by varchar(255),
        password_hash varchar(255),
        updated_by varchar(255),
        type enum ('GOOGLE','LOCAL'),
        primary key (user_id)
    );

    create table authentication_roles (
        authentication_user_id varchar(128) not null,
        roles enum ('ADMIN','CUSTOMER','LIVREUR','PARTNER','SUPER_ADMIN')
    );

    create table backoffice_app_config (
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        activity_sector varchar(255),
        city varchar(255),
        contact_email varchar(255),
        contact_phone varchar(255),
        created_by varchar(255),
        logo_url varchar(255),
        slogan varchar(255),
        store_name varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table backoffice_free_shipping_rule (
        enabled boolean not null,
        threshold_amount float(53) not null,
        created_at timestamp(6),
        updated_at timestamp(6),
        id varchar(36) not null,
        progress_message_template varchar(2000),
        unlocked_message varchar(2000),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table backoffice_integration_setting (
        google_analytics_connected boolean,
        paydunya_connected boolean,
        sendinblue_connected boolean,
        slack_connected boolean,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        paydunya_master_key varchar(4000),
        paydunya_private_key varchar(4000),
        paydunya_token varchar(4000),
        sendinblue_api_key varchar(4000),
        slack_webhook_url varchar(4000),
        created_by varchar(255),
        google_analytics_measurement_id varchar(255),
        paydunya_mode varchar(255),
        paydunya_public_key varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table backoffice_notification_preference (
        enabled boolean not null,
        created_at timestamp(6),
        updated_at timestamp(6),
        pref_key varchar(128) not null,
        created_by varchar(255),
        label varchar(255),
        updated_by varchar(255),
        primary key (pref_key)
    );

    create table backoffice_security_setting (
        admin2fa_enabled boolean not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table backoffice_shipping_method (
        cost_amount float(53) not null,
        enabled boolean not null,
        is_default boolean not null,
        sort_order integer,
        created_at timestamp(6),
        updated_at timestamp(6),
        id varchar(36) not null,
        description varchar(2000),
        code varchar(255) not null,
        created_by varchar(255),
        label varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table backoffice_social_link (
        sort_order integer,
        created_at timestamp(6),
        updated_at timestamp(6),
        id varchar(36) not null,
        url varchar(2000) not null,
        created_by varchar(255),
        platform varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table blog_post (
        featured boolean,
        created_at timestamp(6),
        id bigint generated by default as identity,
        published_at timestamp(6),
        updated_at timestamp(6),
        excerpt varchar(1000),
        content varchar(10000),
        author varchar(255),
        category varchar(255),
        created_by varchar(255),
        image_url varchar(255),
        read_time varchar(255),
        title varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table cart (
        id integer generated by default as identity,
        created_at timestamp(6),
        updated_at timestamp(6),
        customer_user_id varchar(128),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table cart_article (
        cart_id integer not null,
        id integer generated by default as identity,
        price_at_added_time float(53),
        quantity integer not null,
        article_id bigint not null,
        created_at timestamp(6),
        updated_at timestamp(6),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table category (
        id integer generated by default as identity,
        is_activated boolean,
        order_idx integer,
        created_at timestamp(6),
        updated_at timestamp(6),
        created_by varchar(255),
        image_url varchar(255),
        name varchar(255) unique,
        parent_slug varchar(255),
        slug varchar(255),
        updated_by varchar(255),
        level enum ('PRINCIPALE','SOUS_CATEGORIE','SOUS_SOUS_CATEGORIE'),
        primary key (id)
    );

    create table customer (
        phone_number varchar(30),
        city varchar(100),
        country varchar(100),
        user_id varchar(128) not null,
        avatar_url varchar(255),
        primary key (user_id)
    );

    create table customer_address (
        is_default boolean not null,
        created_at timestamp(6),
        updated_at timestamp(6),
        postal_code varchar(20),
        phone_number varchar(30),
        city varchar(100),
        country varchar(100),
        label varchar(100),
        customer_id varchar(128) not null,
        id varchar(128) not null,
        created_by varchar(255),
        line1 varchar(255),
        line2 varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table discount (
        discount_value float(53) not null,
        is_active boolean,
        min_order_amount float(53),
        usage_count integer,
        usage_max integer,
        usage_max_per_user integer,
        created_at timestamp(6),
        end_at timestamp(6),
        id bigint generated by default as identity,
        start_at timestamp(6),
        updated_at timestamp(6),
        code varchar(255) not null unique,
        created_by varchar(255),
        description varchar(255),
        target_id varchar(255),
        updated_by varchar(255),
        target enum ('BOUTIQUE','GLOBAL','UTILISATEUR') not null,
        type enum ('FIXED','PERCENTAGE') not null,
        primary key (id)
    );

    create table email_message (
        attempt_count integer not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        next_retry_at timestamp(6),
        sent_at timestamp(6),
        updated_at timestamp(6),
        last_error varchar(2000),
        body varchar(10000) not null,
        created_by varchar(255),
        subject varchar(255) not null,
        updated_by varchar(255),
        status enum ('FAILED','PENDING','SENT') not null,
        primary key (id)
    );

    create table email_message_recipient (
        message_id bigint not null,
        recipient varchar(255) not null
    );

    create table loyalty_config (
        points_per_fcfa float(53) not null,
        retention_days integer not null,
        value_per_point_fcfa float(53) not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table loyalty_point_adjustment (
        delta_points integer not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        customer_user_id varchar(128) not null,
        created_by varchar(255),
        reason varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table loyalty_tier (
        members integer not null,
        min_points integer not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        benefits varchar(255),
        created_by varchar(255),
        name varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table marketing_campaign (
        attempts integer not null,
        budget_spent float(53),
        click_rate float(53),
        open_rate float(53),
        revenue float(53),
        created_at timestamp(6),
        date_creation timestamp(6),
        failed_count bigint not null,
        id bigint generated by default as identity,
        next_retry_at timestamp(6),
        scheduled_at timestamp(6),
        sent_at timestamp(6),
        sent_count bigint not null,
        target_count bigint not null,
        updated_at timestamp(6),
        subject varchar(200),
        last_error varchar(2000),
        content varchar(10000),
        created_by varchar(255),
        name varchar(255) not null,
        updated_by varchar(255),
        audience enum ('ALL','CLIENTS','NEWSLETTER'),
        status enum ('ACTIVE','FINISHED','SCHEDULED') not null,
        type enum ('EMAIL','SMS','SOCIAL') not null,
        primary key (id)
    );

    create table marketing_campaign_delivery (
        attempts integer not null,
        campaign_id bigint not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        next_retry_at timestamp(6),
        sent_at timestamp(6),
        last_error varchar(2000),
        recipient varchar(255) not null,
        channel enum ('EMAIL','SMS','SOCIAL') not null,
        status enum ('FAILED','PENDING','SENT') not null,
        primary key (id),
        constraint uk_marketing_delivery_campaign_recipient unique (campaign_id, recipient)
    );

    create table newsletter_subscriber (
        created_at timestamp(6),
        unsubscribed_at timestamp(6),
        updated_at timestamp(6),
        id varchar(36) not null,
        created_by varchar(255),
        email varchar(255) not null unique,
        updated_by varchar(255),
        source enum ('BACKOFFICE','IMPORT','UNKNOWN','WEBSITE') not null,
        status enum ('SUBSCRIBED','UNSUBSCRIBED') not null,
        primary key (id)
    );

    create table order_article (
        price_at_order float(53),
        quantity integer,
        article_id bigint,
        created_at timestamp(6),
        id bigint generated by default as identity,
        order_id bigint,
        updated_at timestamp(6),
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table orders (
        amount float(53) not null,
        currency varchar(3),
        created_at timestamp(6),
        delivery_date timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        customer_user_id varchar(128) not null,
        created_by varchar(255),
        tracking_number varchar(255),
        updated_by varchar(255),
        current_status enum ('CANCELED','DELIVERED','DELIVERY_IN_PROGRESS','PAID','PENDING','PROCESSING','READY_TO_DELIVER','REFUNDED') not null,
        primary key (id)
    );

    create table partner (
        contract_accepted boolean not null,
        shop_id bigint unique,
        phone_number varchar(20),
        ninea varchar(64),
        city varchar(100),
        country varchar(100),
        iban varchar(128),
        rccm varchar(128),
        rib varchar(128),
        swift varchar(128),
        user_id varchar(128) not null,
        head_office_address varchar(500),
        business_registration_document_url varchar(1000),
        id_document_url varchar(1000),
        ninea_document_url varchar(1000),
        supporting_documents_zip_url varchar(1000),
        account_holder varchar(255),
        bank_name varchar(255),
        password_hash varchar(255),
        registration_status enum ('REJECTED','STEP_1_PENDING','STEP_2_PENDING','STEP_3_PENDING','STEP_4_PENDING','UNDER_REVIEW','VERIFIED') not null,
        primary key (user_id)
    );

    create table password_reset_token (
        used boolean not null,
        created_at timestamp(6),
        expiry_date timestamp(6) not null,
        updated_at timestamp(6),
        id uuid not null,
        user_id varchar(128) not null,
        code varchar(255) not null,
        created_by varchar(255),
        updated_by varchar(255),
        purpose enum ('ADMIN_LOGIN_2FA','PASSWORD_RESET') not null,
        primary key (id)
    );

    create table payment (
        amount numeric(38,2),
        created_at timestamp(6),
        id bigint generated by default as identity,
        order_id bigint,
        payment_date timestamp(6),
        updated_at timestamp(6),
        cancel_url varchar(255),
        created_by varchar(255),
        currency VARCHAR(3) DEFAULT 'XOF',
        customer_email varchar(255),
        customer_name varchar(255),
        customer_phone varchar(255),
        description TEXT,
        failure_reason TEXT,
        invoice_token varchar(255),
        paydunya_hash varchar(255),
        receipt_url varchar(255),
        return_url varchar(255),
        transaction_id varchar(255),
        updated_by varchar(255),
        operator enum ('CARD','CARD_CI','CARD_SENEGAL','MTN_MONEY_CI','MTN_MONEY_SENEGAL','ORANGE_MONEY_CI','ORANGE_MONEY_SENEGAL','WAVE_CI','WAVE_SENEGAL'),
        status VARCHAR(20) DEFAULT 'PENDING',
        primary key (id)
    );

    create table payment_transactions (
        created_at timestamp(6),
        id bigint generated by default as identity,
        payment_id bigint not null,
        updated_at timestamp(6),
        created_by varchar(255),
        details TEXT,
        source varchar(255),
        status_at_time varchar(255),
        transaction_type varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table product_review (
        rating integer not null,
        validated boolean not null,
        article_id bigint not null,
        created_at timestamp(6),
        deleted_at timestamp(6),
        id bigint generated by default as identity,
        like_count bigint not null,
        report_count bigint not null,
        updated_at timestamp(6),
        customer_id varchar(128) not null,
        content TEXT not null,
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table product_review_like (
        created_at timestamp(6),
        id bigint generated by default as identity,
        review_id bigint not null,
        updated_at timestamp(6),
        user_id varchar(128) not null,
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id),
        constraint uk_product_review_like_user_review unique (review_id, user_id)
    );

    create table product_review_report (
        created_at timestamp(6),
        id bigint generated by default as identity,
        review_id bigint not null,
        updated_at timestamp(6),
        user_id varchar(128) not null,
        created_by varchar(255),
        details TEXT,
        reason varchar(255) not null,
        updated_by varchar(255),
        primary key (id),
        constraint uk_product_review_report_user_review unique (review_id, user_id)
    );

    create table refresh_token (
        revoked boolean not null,
        created_at timestamp(6),
        expires_at timestamp(6) with time zone not null,
        updated_at timestamp(6),
        id uuid not null,
        user_id varchar(128) not null,
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table refunds (
        amount numeric(38,2),
        created_at timestamp(6),
        id bigint generated by default as identity,
        payment_id bigint not null,
        processed_date timestamp(6),
        updated_at timestamp(6),
        created_by varchar(255),
        reason TEXT,
        refund_id varchar(255),
        status VARCHAR(20) DEFAULT 'PENDING',
        updated_by varchar(255),
        primary key (id)
    );

    create table return_request (
        created_at timestamp(6),
        id bigint generated by default as identity,
        order_id bigint not null,
        updated_at timestamp(6),
        order_number varchar(64) not null,
        reason varchar(100) not null,
        created_by varchar(255),
        details TEXT,
        email varchar(255) not null,
        updated_by varchar(255),
        status enum ('APPROVED','CLOSED','COMPLETED','REFUNDED','REJECTED','SUBMITTED','UNDER_REVIEW') not null,
        primary key (id)
    );

    create table return_request_item (
        quantity integer not null,
        unit_price float(53),
        article_id bigint not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        return_request_id bigint not null,
        updated_at timestamp(6),
        article_name varchar(255) not null,
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table security_activity (
        created_at timestamp(6),
        event_at timestamp(6) not null,
        id bigint generated by default as identity,
        updated_at timestamp(6),
        method varchar(16),
        status varchar(64) not null,
        action varchar(128) not null,
        ip varchar(128),
        user_id varchar(128),
        summary varchar(512),
        created_by varchar(255),
        path varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table shipment (
        cost float(53),
        eta date,
        created_at timestamp(6),
        delivered_at timestamp(6),
        delivery_code_generated_at timestamp(6),
        id bigint generated by default as identity,
        scanned_at timestamp(6),
        updated_at timestamp(6),
        carrier varchar(255),
        courier_name varchar(255),
        courier_phone varchar(255),
        courier_reference varchar(255),
        courier_user varchar(255),
        created_by varchar(255),
        delivery_code varchar(255),
        order_id varchar(255) not null,
        tracking_id varchar(255),
        updated_by varchar(255),
        status enum ('ECHEC','EN_COURS','EN_PREPARATION','LIVREE') not null,
        primary key (id)
    );

    create table shop (
        main_category_id integer not null,
        created_at timestamp(6),
        shop_id bigint generated by default as identity,
        updated_at timestamp(6),
        shop_description varchar(1000),
        background_url varchar(255) not null,
        created_by varchar(255),
        description varchar(255) not null,
        logo_url varchar(255) not null,
        shop_name varchar(255) not null,
        updated_by varchar(255),
        status enum ('PRINCIPALE','SOUS_CATEGORIE','SOUS_SOUS_CATEGORIE') not null,
        primary key (shop_id)
    );

    create table status_history (
        changed_at timestamp(6) not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        order_id bigint not null,
        updated_at timestamp(6),
        comment varchar(255),
        created_by varchar(255),
        updated_by varchar(255),
        status enum ('CANCELED','DELIVERED','DELIVERY_IN_PROGRESS','PAID','PENDING','PROCESSING','READY_TO_DELIVER','REFUNDED') not null,
        primary key (id)
    );

    create table stock (
        best_before date,
        quantity_available integer not null,
        quantity_reserved integer not null,
        article_id bigint not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        created_by varchar(255),
        lot varchar(255),
        updated_by varchar(255),
        primary key (id)
    );

    create table stock_movement (
        quantity integer not null,
        stock_after integer not null,
        stock_before integer not null,
        article_id bigint not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        created_by varchar(255),
        reference varchar(255),
        updated_by varchar(255),
        type enum ('AJUSTEMENT','ENTREE','SORTIE') not null,
        primary key (id)
    );

    create table ticket_event (
        available boolean,
        price float(53),
        created_at timestamp(6),
        event_date timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        description varchar(2000),
        category varchar(255),
        created_by varchar(255),
        image_url varchar(255),
        location varchar(255),
        title varchar(255) not null,
        updated_by varchar(255),
        primary key (id)
    );

    create table user_entity (
        blocked boolean not null,
        email_verified boolean not null,
        created_at timestamp(6),
        updated_at timestamp(6),
        user_type varchar(31) not null,
        user_id varchar(128) not null,
        created_by varchar(255),
        email varchar(255) not null,
        first_name varchar(255),
        last_name varchar(255),
        updated_by varchar(255),
        primary key (user_id)
    );

    create table wishlist (
        article_id bigint not null,
        created_at timestamp(6),
        id bigint generated by default as identity,
        updated_at timestamp(6),
        customer_user_id varchar(128) not null,
        created_by varchar(255),
        updated_by varchar(255),
        primary key (id),
        unique (customer_user_id, article_id)
    );

    create index idx_article_status_updated_at 
       on article (status, updated_at);

    create index idx_article_status_created_at 
       on article (status, created_at);

    create index idx_article_featured_status_updated_at 
       on article (is_featured, status, updated_at);

    create index idx_article_bestseller_status_updated_at 
       on article (is_best_seller, status, updated_at);

    create index idx_article_flashsale_status_ends_at 
       on article (is_flash_sale, status, flash_sale_ends_at);

    create index idx_article_reference_partner 
       on article (reference_partner);

